import{_ as a,o as r,c as t,a3 as l}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse(`{"title":"27. Public Holidays","description":"","frontmatter":{"title":"27. Public Holidays","eba":"Children's Services Award 2010","topics":["leave","annual-leave","public-holidays","hours","rosters","employment","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/leave/27-public-holidays.md","filePath":"ebas/childrens-services/leave/27-public-holidays.md"}`),o={name:"ebas/childrens-services/leave/27-public-holidays.md"};function i(s,e,d,n,p,c){return r(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="_27-public-holidays" tabindex="-1">27. Public Holidays <a class="header-anchor" href="#_27-public-holidays" aria-label="Permalink to &quot;27. Public Holidays&quot;">​</a></h1><ol><li><p>Public holidays are provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p></li><li><p>An employer and employee may agree to substitute another day for a day that would otherwise be a public holiday under the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p></li><li><p>An employer and employee may agree to substitute another part-day for a part-day that would otherwise be a part-day public holiday under the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p></li><li><p>Additional arrangements for full-time employees</p></li></ol><p>a. A full-time employee whose rostered day off falls on a public holiday must, subject to clause 27.2, either:</p><pre><code>i.  be paid an extra day&#39;s pay;

ii. be provided with an alternative day off within 28 days; or

iii. receive an additional day&#39;s annual leave.
</code></pre><p>b. If a public holiday is a part-day public holiday, then clause 27.4(a) applies on a pro-rata basis for the number of ordinary hours on the part-day public holiday.</p><p>[27.4(b) renumbered as 27.4(c) and varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr747480.htm" target="_blank" rel="noreferrer">PR747480</a> ppc 14Nov22]</p><p>c. A full-time employee who works on a public holiday is entitled to a substitute day or part-day as provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p><p>Plain language terms: public holiday pay.</p>`,8)])])}const y=a(o,[["render",i]]);export{h as __pageData,y as default};
